class FfiConverterTypeStockTechnicalClient : FfiConverter<StockTechnicalClient, IntPtr>
{
    public static FfiConverterTypeStockTechnicalClient INSTANCE =
        new FfiConverterTypeStockTechnicalClient();

    public override IntPtr Lower(StockTechnicalClient value)
    {
        return value.CallWithPointer(thisPtr => thisPtr);
    }

    public override StockTechnicalClient Lift(IntPtr value)
    {
        return new StockTechnicalClient(value);
    }

    public override StockTechnicalClient Read(BigEndianStream stream)
    {
        return Lift(new IntPtr(stream.ReadLong()));
    }

    public override int AllocationSize(StockTechnicalClient value)
    {
        return 8;
    }

    public override void Write(StockTechnicalClient value, BigEndianStream stream)
    {
        stream.WriteLong(Lower(value).ToInt64());
    }
}

/// <summary>
/// WebSocket client for real-time market data streaming
///
/// Wraps the core WebSocketClient and forwards messages to the provided
/// WebSocketListener implementation via a background task.
/// </summary>
public interface IWebSocketClient
{
    /// <summary>
    /// Connect to the WebSocket server
    ///
    /// Establishes connection, authenticates, and starts a background task
    /// to forward messages to the listener.
    ///
    /// # Errors
    ///
    /// Returns error if connection or authentication fails.
    /// </summary>
    /// <exception cref="MarketDataException"></exception>
    Task Connect();

    /// <summary>
    /// Disconnect from the WebSocket server
    ///
    /// Gracefully closes the connection and stops the message forwarding task.
    /// </summary>
    Task Disconnect();

    /// <summary>
    /// Check if the client has been shut down
    /// </summary>
    bool IsClosed();

    /// <summary>
    /// Check if the client is currently connected
    /// </summary>
    bool IsConnected();

    /// <summary>
    /// Send a ping message to the server
    ///
    /// # Arguments
    /// * `state` - Optional state string echoed back in the pong response
    /// </summary>
    /// <exception cref="MarketDataException"></exception>
    Task Ping(string? @state);

    /// <summary>
    /// Query the server for current subscriptions
    /// </summary>
    /// <exception cref="MarketDataException"></exception>
    Task QuerySubscriptions();

    /// <summary>
    /// Subscribe to a channel for a symbol
    ///
    /// # Arguments
    /// * `channel` - Channel name (e.g., "trades", "candles", "books")
    /// * `symbol` - Symbol to subscribe (e.g., "2330")
    ///
    /// # Errors
    ///
    /// Returns error if not connected or subscription fails.
    /// </summary>
    /// <exception cref="MarketDataException"></exception>
    Task Subscribe(string @channel, string @symbol);

    /// <summary>
    /// Unsubscribe from a channel for a symbol
    ///
    /// # Arguments
    /// * `channel` - Channel name
    /// * `symbol` - Symbol to unsubscribe
    ///
    /// # Errors
    ///
    /// Returns error if not connected.
    /// </summary>
    /// <exception cref="MarketDataException"></exception>
    Task Unsubscribe(string @channel, string @symbol);
}

/// <summary>
/// WebSocket client for real-time market data streaming
///
/// Wraps the core WebSocketClient and forwards messages to the provided
/// WebSocketListener implementation via a background task.
/// </summary>
public class WebSocketClient : IWebSocketClient, IDisposable
{
    protected IntPtr pointer;
    private int _wasDestroyed = 0;
    private long _callCounter = 1;

    public WebSocketClient(IntPtr pointer)
    {
        this.pointer = pointer;
    }

    ~WebSocketClient()
    {
        Destroy();
    }

    /// <summary>
    /// Create a new WebSocket client for stock market data
    ///
    /// # Arguments
    /// * `api_key` - Fugle API key for authentication
    /// * `listener` - Callback interface for receiving WebSocket events
    /// </summary>
    public WebSocketClient(string @apiKey, WebSocketListener @listener)
        : this(
            _UniffiHelpers.RustCall(
                (ref UniffiRustCallStatus _status) =>
                    _UniFFILib.uniffi_marketdata_uniffi_fn_constructor_websocketclient_new(
                        FfiConverterString.INSTANCE.Lower(@apiKey),
                        FfiConverterTypeWebSocketListener.INSTANCE.Lower(@listener),
                        ref _status
                    )
            )
        ) { }

    protected void FreeRustArcPtr()
    {
        _UniffiHelpers.RustCall(
            (ref UniffiRustCallStatus status) =>
            {
                _UniFFILib.uniffi_marketdata_uniffi_fn_free_websocketclient(
                    this.pointer,
                    ref status
                );
            }
        );
    }

    protected IntPtr CloneRustArcPtr()
    {
        return _UniffiHelpers.RustCall(
            (ref UniffiRustCallStatus status) =>
            {
                return _UniFFILib.uniffi_marketdata_uniffi_fn_clone_websocketclient(
                    this.pointer,
                    ref status
                );
            }
        );
    }

    public void Destroy()
    {
        // Only allow a single call to this method.
        if (Interlocked.CompareExchange(ref _wasDestroyed, 1, 0) == 0)
        {
            // This decrement always matches the initial count of 1 given at creation time.
            if (Interlocked.Decrement(ref _callCounter) == 0)
            {
                FreeRustArcPtr();
            }
        }
    }

    public void Dispose()
    {
        Destroy();
        GC.SuppressFinalize(this); // Suppress finalization to avoid unnecessary GC overhead.
    }

    private void IncrementCallCounter()
    {
        // Check and increment the call counter, to keep the object alive.
        // This needs a compare-and-set retry loop in case of concurrent updates.
        long count;
        do
        {
            count = Interlocked.Read(ref _callCounter);
            if (count == 0L)
                throw new System.ObjectDisposedException(
                    String.Format("'{0}' object has already been destroyed", this.GetType().Name)
                );
            if (count == long.MaxValue)
                throw new System.OverflowException(
                    String.Format("'{0}' call counter would overflow", this.GetType().Name)
                );
        } while (Interlocked.CompareExchange(ref _callCounter, count + 1, count) != count);
    }

    private void DecrementCallCounter()
    {
        // This decrement always matches the increment we performed above.
        if (Interlocked.Decrement(ref _callCounter) == 0)
        {
            FreeRustArcPtr();
        }
    }

    internal void CallWithPointer(Action<IntPtr> action)
    {
        IncrementCallCounter();
        try
        {
            action(CloneRustArcPtr());
        }
        finally
        {
            DecrementCallCounter();
        }
    }

    internal T CallWithPointer<T>(Func<IntPtr, T> func)
    {
        IncrementCallCounter();
        try
        {
            return func(CloneRustArcPtr());
        }
        finally
        {
            DecrementCallCounter();
        }
    }

