/// <summary>
/// Error type for UniFFI bindings
///
/// Maps to MarketDataError in the UDL file. Each variant becomes an exception
/// in the target language with the error message preserved.
///
/// Note: This is a FLAT enum per UniFFI constraints - no nested error types.
/// </summary>
public class MarketDataException : UniffiException
{
    MarketDataException()
        : base() { }

    MarketDataException(String @Message)
        : base(@Message) { }

    // Each variant is a nested class


    public class NetworkException : MarketDataException
    {
        // Members
        public string @msg;

        // Constructor
        public NetworkException(string @msg)
            : base("@msg" + "=" + @msg)
        {
            this.@msg = @msg;
        }
    }

    public class AuthException : MarketDataException
    {
        // Members
        public string @msg;

        // Constructor
        public AuthException(string @msg)
            : base("@msg" + "=" + @msg)
        {
            this.@msg = @msg;
        }
    }

    public class RateLimitException : MarketDataException
    {
        // Members
        public string @msg;

        // Constructor
        public RateLimitException(string @msg)
            : base("@msg" + "=" + @msg)
        {
            this.@msg = @msg;
        }
    }

    public class InvalidSymbol : MarketDataException
    {
        // Members
        public string @msg;

        // Constructor
        public InvalidSymbol(string @msg)
            : base("@msg" + "=" + @msg)
        {
            this.@msg = @msg;
        }
    }

    public class ParseException : MarketDataException
    {
        // Members
        public string @msg;

        // Constructor
        public ParseException(string @msg)
            : base("@msg" + "=" + @msg)
        {
            this.@msg = @msg;
        }
    }

    public class TimeoutException : MarketDataException
    {
        // Members
        public string @msg;

        // Constructor
        public TimeoutException(string @msg)
            : base("@msg" + "=" + @msg)
        {
            this.@msg = @msg;
        }
    }

    public class WebSocketException : MarketDataException
    {
        // Members
        public string @msg;

        // Constructor
        public WebSocketException(string @msg)
            : base("@msg" + "=" + @msg)
        {
            this.@msg = @msg;
        }
    }

    public class ClientClosed : MarketDataException
    {
        public ClientClosed()
            : base() { }
    }

    public class ConfigException : MarketDataException
    {
        // Members
        public string @msg;

        // Constructor
        public ConfigException(string @msg)
            : base("@msg" + "=" + @msg)
        {
            this.@msg = @msg;
        }
    }

    public class ApiException : MarketDataException
    {
        // Members
        public string @msg;

        // Constructor
        public ApiException(string @msg)
            : base("@msg" + "=" + @msg)
        {
            this.@msg = @msg;
        }
    }

    public class Other : MarketDataException
    {
        // Members
        public string @msg;

        // Constructor
        public Other(string @msg)
            : base("@msg" + "=" + @msg)
        {
            this.@msg = @msg;
        }
    }
}

class FfiConverterTypeMarketDataError
    : FfiConverterRustBuffer<MarketDataException>,
        CallStatusErrorHandler<MarketDataException>
{
    public static FfiConverterTypeMarketDataError INSTANCE = new FfiConverterTypeMarketDataError();

    public override MarketDataException Read(BigEndianStream stream)
    {
        var value = stream.ReadInt();
        switch (value)
        {
            case 1:
                return new MarketDataException.NetworkException(
                    FfiConverterString.INSTANCE.Read(stream)
                );
            case 2:
                return new MarketDataException.AuthException(
                    FfiConverterString.INSTANCE.Read(stream)
                );
            case 3:
                return new MarketDataException.RateLimitException(
                    FfiConverterString.INSTANCE.Read(stream)
                );
            case 4:
                return new MarketDataException.InvalidSymbol(
                    FfiConverterString.INSTANCE.Read(stream)
                );
            case 5:
                return new MarketDataException.ParseException(
                    FfiConverterString.INSTANCE.Read(stream)
                );
            case 6:
                return new MarketDataException.TimeoutException(
                    FfiConverterString.INSTANCE.Read(stream)
                );
            case 7:
                return new MarketDataException.WebSocketException(
                    FfiConverterString.INSTANCE.Read(stream)
                );
            case 8:
                return new MarketDataException.ClientClosed();
            case 9:
                return new MarketDataException.ConfigException(
                    FfiConverterString.INSTANCE.Read(stream)
                );
            case 10:
                return new MarketDataException.ApiException(
                    FfiConverterString.INSTANCE.Read(stream)
                );
            case 11:
                return new MarketDataException.Other(FfiConverterString.INSTANCE.Read(stream));
            default:
                throw new InternalException(
                    String.Format(
                        "invalid error value '{0}' in FfiConverterTypeMarketDataError.Read()",
                        value
                    )
                );
        }
    }

    public override int AllocationSize(MarketDataException value)
    {
        switch (value)
        {
            case MarketDataException.NetworkException variant_value:
                return 4 + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);

            case MarketDataException.AuthException variant_value:
                return 4 + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);

            case MarketDataException.RateLimitException variant_value:
                return 4 + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);

            case MarketDataException.InvalidSymbol variant_value:
                return 4 + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);

            case MarketDataException.ParseException variant_value:
                return 4 + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);

            case MarketDataException.TimeoutException variant_value:
                return 4 + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);

            case MarketDataException.WebSocketException variant_value:
                return 4 + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);

            case MarketDataException.ClientClosed variant_value:
                return 4;

            case MarketDataException.ConfigException variant_value:
                return 4 + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);

            case MarketDataException.ApiException variant_value:
                return 4 + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);

            case MarketDataException.Other variant_value:
                return 4 + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);
            default:
                throw new InternalException(
                    String.Format(
                        "invalid error value '{0}' in FfiConverterTypeMarketDataError.AllocationSize()",
                        value
                    )
                );
        }
    }

    public override void Write(MarketDataException value, BigEndianStream stream)
    {
        switch (value)
        {
            case MarketDataException.NetworkException variant_value:
                stream.WriteInt(1);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            case MarketDataException.AuthException variant_value:
                stream.WriteInt(2);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            case MarketDataException.RateLimitException variant_value:
                stream.WriteInt(3);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            case MarketDataException.InvalidSymbol variant_value:
                stream.WriteInt(4);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            case MarketDataException.ParseException variant_value:
                stream.WriteInt(5);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            case MarketDataException.TimeoutException variant_value:
                stream.WriteInt(6);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            case MarketDataException.WebSocketException variant_value:
                stream.WriteInt(7);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            case MarketDataException.ClientClosed variant_value:
                stream.WriteInt(8);
                break;
            case MarketDataException.ConfigException variant_value:
                stream.WriteInt(9);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            case MarketDataException.ApiException variant_value:
                stream.WriteInt(10);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            case MarketDataException.Other variant_value:
                stream.WriteInt(11);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            default:
                throw new InternalException(
                    String.Format(
                        "invalid error value '{0}' in FfiConverterTypeMarketDataError.Write()",
                        value
                    )
                );
        }
    }
}

/// <summary>
/// Endpoint type for WebSocket connection
/// </summary>
public enum WebSocketEndpoint : int
{
    /// <summary>
    /// Stock market data endpoint
    /// </summary>
    Stock,

    /// <summary>
    /// Futures and options market data endpoint
    /// </summary>
    FutOpt,
}

class FfiConverterTypeWebSocketEndpoint : FfiConverterRustBuffer<WebSocketEndpoint>
{
    public static FfiConverterTypeWebSocketEndpoint INSTANCE =
        new FfiConverterTypeWebSocketEndpoint();

    public override WebSocketEndpoint Read(BigEndianStream stream)
    {
        var value = stream.ReadInt() - 1;
        if (Enum.IsDefined(typeof(WebSocketEndpoint), value))
        {
            return (WebSocketEndpoint)value;
        }
        else
        {
            throw new InternalException(
                String.Format(
                    "invalid enum value '{0}' in FfiConverterTypeWebSocketEndpoint.Read()",
                    value
                )
            );
        }
    }

    public override int AllocationSize(WebSocketEndpoint value)
    {
        return 4;
    }

    public override void Write(WebSocketEndpoint value, BigEndianStream stream)
    {
        stream.WriteInt((int)value + 1);
    }
}

class FfiConverterOptionalUInt32 : FfiConverterRustBuffer<uint?>
{
    public static FfiConverterOptionalUInt32 INSTANCE = new FfiConverterOptionalUInt32();

    public override uint? Read(BigEndianStream stream)
    {
        if (stream.ReadByte() == 0)
        {
            return null;
        }
        return FfiConverterUInt32.INSTANCE.Read(stream);
    }

    public override int AllocationSize(uint? value)
    {
        if (value == null)
        {
            return 1;
        }
        else
        {
            return 1 + FfiConverterUInt32.INSTANCE.AllocationSize((uint)value);
        }
    }

    public override void Write(uint? value, BigEndianStream stream)
    {
        if (value == null)
        {
            stream.WriteByte(0);
        }
        else
        {
            stream.WriteByte(1);
            FfiConverterUInt32.INSTANCE.Write((uint)value, stream);
        }
    }
}

